const exec = $json.execution;
const wf = $json.workflow;

return [{
  json: {
    workflowId: wf.id,
    workflowName: wf.name,
    executionUrl: exec.url,
    errorName: exec.error.name,
    errorMessage: exec.error.message,
    errorStack: (exec.error.stack || '').substring(0, 500),
    failedNode: exec.lastNodeExecuted,
    timestamp: new Date().toISOString(),
    dedup_key: wf.id + ':' + exec.error.message
  }
}];

// Dedup: si el mismo error se repitio en los ultimos 30 min, skip
const key = $json.dedup_key;
const now = Date.now();
const THROTTLE_MS = 30 * 60 * 1000; // 30 minutos

// Usar staticData para persistir entre ejecuciones
const staticData = $getWorkflowStaticData('global');
if (!staticData.lastErrors) staticData.lastErrors = {};

const lastSeen = staticData.lastErrors[key];
if (lastSeen && (now - lastSeen) < THROTTLE_MS) {
  // Mismo error dentro del throttle window -> skip
  return [{ json: { ...($json), skip: true, reason: 'Dedup: mismo error en ultimos 30 min' } }];
}

// Registrar este error
staticData.lastErrors[key] = now;

// Limpiar errores viejos (> 2h)
for (const k of Object.keys(staticData.lastErrors)) {
  if (now - staticData.lastErrors[k] > 2 * 60 * 60 * 1000) {
    delete staticData.lastErrors[k];
  }
}

return [{ json: { ...($json), skip: false } }];

